  ('dietitian-moex-01644', 'dietitian', 'dietitian-moex-108-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者不包含在2025衛生福利政策白皮書「健全青少年健康發展」的策略？', '["養成攝取足夠鈣質的健康飲食行為", "養成低鹽、低糖、少飽和脂肪等健康飲食行為", "攝取足夠蛋白質食物以預防肌少症發生", "強調健康體位及辦理營養教育，預防營養不良、缺鐵性貧血和肥胖症"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "c34c8cd3bc2a", "answer_pdf_sha1": "5b299ec7f022", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01645', 'dietitian', 'dietitian-moex-108-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在補充嬰兒副食品的順序中，下列何種食物應最後給予？', '["米糊", "果泥", "蔬菜泥", "蒸蛋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "c34c8cd3bc2a", "answer_pdf_sha1": "5b299ec7f022", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01646', 'dietitian', 'dietitian-moex-108-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '老師宣導不喝含糖飲料，但是同學卻發現老師每天都喝含糖飲料，學生因此降低原本想要少喝含 糖飲料的意願。請問此結果主要是受「整合行為模式」中的那一個因素所影響？', '["知覺規範中的「觀察性規範」", "過往經驗所產生的「經驗性態度」", "執行不喝含糖飲料的「控制信念」", "不喝含糖飲料的「行為信念」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "c34c8cd3bc2a", "answer_pdf_sha1": "5b299ec7f022", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01647', 'dietitian', 'dietitian-moex-108-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據教育部民國102年所公布之「學校午餐食物內容及營養基準」，國高中學生午餐鈉含量不應 超過多少毫克？', '["330", "400", "800", "960"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "c34c8cd3bc2a", "answer_pdf_sha1": "5b299ec7f022", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01648', 'dietitian', 'dietitian-moex-108-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '處理學校午餐疑似食品中毒事件，下列敘述何者錯誤？', '["儘速將患者送醫，並通知當地衛生主管機關", "依據教育部各級學校發生疑似食品中毒事件處理作業流程處置", "校園食品中毒屬於甲級法定通報事件，至遲不得逾24小時於教育部資安通報網通報", "若確認為廠商之責任，學校應依契約規定辦理，包括違約記點、繳納違約金、契約終止等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "c34c8cd3bc2a", "answer_pdf_sha1": "5b299ec7f022", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01649', 'dietitian', 'dietitian-moex-108-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某國小進用的廚工，根據「學校餐廳廚房員生消費合作社衛生管理辦法」，每年要參加多少小時 的衛生或營養講習，才符合學校餐飲從業人員的規定？', '["2", "4", "6", "8"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "c34c8cd3bc2a", "answer_pdf_sha1": "5b299ec7f022", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01650', 'dietitian', 'dietitian-moex-108-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '世界衛生組織於2015年發布之「Guideline：Sugars intake for adults and children」建議每日游離 糖（free sugar）之熱量不超過攝取總熱量的百分之多少？', '["6", "8", "10", "12"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "c34c8cd3bc2a", "answer_pdf_sha1": "5b299ec7f022", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
